import axios from 'axios';

const useApi = () => {
    const ownerPhone = localStorage.getItem("phone") || null;

    const fetchData = async (url) => {
        try {
            const response = await axios.get(url, {
                params: {
                    phone: ownerPhone,
                },
            });

            return response;
        } catch (err) {
            console.log(err.message || 'Error fetching data');
        }
    };

    return { fetchData };
};

export default useApi;